trigger.body:
 v_count NUMBER:=0;
 v_AmtRes NUMBER;

BEGIN

  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF; 

  IF (UPDATING)THEN
    IF (:new.posted = 'Y' OR :new.docstatus = 'CO') THEN -- Begin is UnPosting

      -- Have a Distribute Cost Center
      SELECT count(*)
      INTO v_count
      FROM ssdccp_distcostcenter CI
      WHERE CI.c_invoice_id = :new.c_invoice_id;

	IF (:NEW.TOTALLINES>0 AND v_count>0) THEN

		SELECT
			COALESCE((SELECT SUM(AMOUNT) AS sum_ 
			FROM ssdccp_distcostcenter 
			WHERE C_INVOICE_ID =  :new.c_invoice_id ),0)
			INTO v_AmtRes
		FROM DUAL;

		IF (v_AmtRes<:NEW.TOTALLINES) THEN
			RAISE_APPLICATION_ERROR(-20000, 'El total distribuido no coincide con el valor de la factura') ;
		END IF;
	END IF;

    END IF;  -- End  is UnPosting
  END IF;

  END SSDCCP_INVOICEPOSTED_TRG
